import{_ as e,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"封剑烙印","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/封剑烙印.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/封剑烙印.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/封剑烙印.md"};function o(d,a,l,_,i,c){return t(),p("div",null,[...a[0]||(a[0]=[r("h1",{id:"封剑烙印",tabindex:"-1"},[b("封剑烙印 "),r("a",{class:"header-anchor",href:"#封剑烙印","aria-label":'Permalink to "封剑烙印"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),n('<h1 id="封剑烙印-1" tabindex="-1">封剑烙印 <a class="header-anchor" href="#封剑烙印-1" aria-label="Permalink to &quot;封剑烙印&quot;">​</a></h1><p>封剑烙印<br> D+600<br> 一次性训练<br> “你的剑呢？”<br> “丢了”<br> “那你为什么还自称剑客？”<br> “因为我剑在心中。”</p><p>封剑烙印是一个出现在烙印者惯用手（这意味着如果你是双利手将会同时出现）上的红色诅咒印记，一般为一道类似剑被铁链封锁的样式。</p><p>[封剑]：持有封剑烙印后，你持有任何造成挥砍伤害的武器进行攻击后，烙印将对你造成不可避免的1点D级诅咒来源的剧痛点数，持续一场景。这是你的烙印在抗拒你手持有形剑的作用。</p><p>[剑意]：即使你难以手持剑，但你心中有剑，你获得一种近战攻击方式，称为[剑意]，其攻击组成方式为[决心+武技+剑+专注：冷静]，造成光能伤害，并在结算伤害时将1点严重伤害转为1点韧性伤害。表现为你凝聚出你内心的剑意进行攻击，这种攻击方式无法正常使用剑类武器进行攻击，但取而代之的是：你在持有棍状物体时，可以用这一攻击方式使用将其作为临时武器进行攻击。</p><p>但同时，[封剑]的效果也会对该攻击方式产生一定的抗拒，一场景一次，你在战斗中使用[剑意]进行攻击，你烙印将对你造成不可避免的1点D级诅咒来源的剧痛点数，持续一场景。</p><p>[不朽剑心]：剑路长行，不悔入道<br> 如果你在一场同级别战斗中使用过[剑意]进行攻击并胜利，你永久获得1点[剑道]，每点[剑道]使你的决心相关检定永久获得2点内在加值，这个效果每影片限一次，[剑道]没有叠加上限，如果你身上的[剑道]大于3点，则你使用[剑意]进行攻击不再会因为[封剑]而获得剧痛点数。</p><p>[剑魂]：剑招万化，剑心其中，剑魂不乱，万招开。<br> 你获得一个名为[剑魂]的强化能量池，其视为[气]的变体，恢复方式同[气]，其关键属性为[决心*2]，且获得其基础用法：<br> 基本用法：你可以支付2点剑魂，令你在某一次洞察检定中获得2dp能量加值。</p><p>【封剑烙印-下属技艺与物品】</p><p>剑步行<br> C+1000<br> 所行如剑出，锐锋无可挡<br> 如果你在一次移动中移动的距离米数为你手持武器的体积倍数，则本次移动具有【剑步】效果，表现为你不断从你刚刚武器的最末端闪现。<br> [剑步]：你的移动视为C级别时空来源的【传送移动】，在移动结束后的下一次[剑意]攻击将具有C级别时空来源的传送攻击效果。</p><p>斩妖邪<br> C+1000<br> 路斩害人妖，城除惑民邪<br> 你的[剑意]进一步增强，在你进行[剑意]攻击时，可令一把临时武器额外具有等同于你【传奇决心*2+2】的武器伤害。</p><p>破河灾<br> C+1000<br> 一剑开洪，护万家灯火周全<br> 你的[剑意]攻击现在会攻击到你触及范围内的所有敌人，并且现在你的触及范围增加12米</p><p>凡尘剑心<br> B+2000<br> 红尘滚滚，人世铅华，洗净后，仍留赤子心，仍向剑道行。<br> 当你具有至少8点[剑意]时，你的决心相关检定获得【8加骰】，每轮开始获得4点仅能够转化为攻击动作中的ap。</p><p>紫竹杖<br> 分类：临时武器<br> 价格：150<br> 一根紫色的硬竹子，体积4，在作为临时武器使用时，使用以下能力：<br> 武器伤害：0L<br> 基础特性：双手，格挡5，威猛1</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
